    // Créer un pipe
    if (pipe(pipefd) == -1) {
        std::cerr << "Erreur de création du pipe" << std::endl;
        return 1;
    }

    // Fork pour créer un processus fils
    pid = fork();
    if (pid == -1) {
        std::cerr << "Erreur de fork" << std::endl;
        return 1;
    }

    if (pid == 0) { // Code du processus fils
        // Fermer le file descriptor d'écriture du pipe
        close(pipefd[1]);
        // Rediriger l'entrée et la sortie du processus fils vers le pipe
        dup2(pipefd[0], 0); // Entrée (stdin)
        dup2(pipefd[0], 1); // Sortie (stdout)
        close(pipefd[0]);   // Fermer les instances superflues
        // Exécuter une commande (ici c'est un exemple)
        execvp("ls", NULL); // Remplace le processus par "ls"
    } else { // Code du processus père
        // Fermer le file descriptor de lecture du pipe
        close(pipefd[0]);
        // Continuez à utiliser le pipe comme nécessaire...
        std::cout << "Fils est en cours d'exécution..." << std::endl;
    }

    return 0;
}
```

